const fs = require('fs');

function parseCsv(text) {
  const lines = text.trim().split(/\r?\n/);
  const headers = lines[0].split(',');
  return lines.slice(1).filter(Boolean).map((line) => {
    const values = [];
    let current = '';
    let inQuotes = false;
    for (let i = 0; i < line.length; i++) {
      const char = line[i];
      if (char === '"') {
        if (inQuotes && line[i + 1] === '"') {
          current += '"';
          i++;
        } else {
          inQuotes = !inQuotes;
        }
      } else if (char === ',' && !inQuotes) {
        values.push(current);
        current = '';
      } else {
        current += char;
      }
    }
    values.push(current);
    return Object.fromEntries(headers.map((header, index) => [header, values[index] ?? '']));
  });
}

function toNumber(value) {
  const parsed = Number(value);
  return Number.isFinite(parsed) ? parsed : null;
}

function sigmoid(value) {
  return 1 / (1 + Math.exp(-value));
}

function decisionLabel(probability, thresholds) {
  if (probability >= thresholds.decline) return 'Decline';
  if (probability >= thresholds.review) return 'Review';
  return 'Approve';
}

function formatUsd(value) {
  return new Intl.NumberFormat('en-US', { style: 'currency', currency: 'USD', maximumFractionDigits: 0 }).format(value);
}

function contributionReason(detail) {
  if (detail.field === 'credit_score') {
    if (detail.rawValue < 600) return `Low credit score (${Math.round(detail.rawValue)}) materially increases default risk.`;
    return `Credit score (${Math.round(detail.rawValue)}) is below the stronger-performing borrower range.`;
  }
  if (detail.field === 'debt_to_income_ratio') {
    return `Debt-to-income ratio (${detail.rawValue.toFixed(2)}) is high relative to the training portfolio.`;
  }
  if (detail.field === 'interest_rate_pct') {
    return `Interest rate (${detail.rawValue.toFixed(2)}%) is elevated versus lower-risk borrowers.`;
  }
  if (detail.field === 'loan_amount_usd') {
    return `Requested loan amount (${formatUsd(detail.rawValue)}) is large for this portfolio.`;
  }
  if (detail.field === 'annual_revenue_usd') {
    return `Annual revenue (${formatUsd(detail.rawValue)}) is low relative to requested credit.`;
  }
  if (detail.field === 'business_age_years') {
    return `Business operating history (${Math.round(detail.rawValue)} years) is limited.`;
  }
  if (detail.field === 'loan_term_months') {
    return `Loan term (${Math.round(detail.rawValue)} months) is longer than the lower-risk cohort.`;
  }
  if (detail.field === 'sector') {
    return `Sector exposure (${detail.rawValue}) has historically produced higher defaults in this sample.`;
  }
  if (detail.field === 'loan_purpose') {
    return `Loan purpose (${detail.rawValue}) has performed worse than the portfolio average.`;
  }
  if (detail.field === 'state') {
    return `State cohort (${detail.rawValue}) has a weaker repayment pattern in the training data.`;
  }
  return `${detail.field} contributes positively to risk.`;
}

function makeBrief(row, probability, decision, reasons) {
  const first = reasons[0] || 'The model found a weaker-than-average repayment profile.';
  const second = reasons[1] || 'No secondary driver rose materially above the rest.';
  const action = decision === 'Decline'
    ? 'Escalate for senior underwriter review and verify bank statements before issuing a final decline.'
    : 'Route to analyst review with refreshed cash-flow documents and recent bank statements.';
  return `RISK SUMMARY: ${decision} at ${(probability * 100).toFixed(1)}% default probability. ${first}\n\nKEY SIGNALS:\n- ${first}\n- ${second}\n\nANALYST ACTION: ${action}`;
}

const rawText = $input.first().json.body ?? $input.first().json.data ?? '';
const rows = parseCsv(rawText);
const modelPath = $env.FINANCEFLOW_MODEL_PATH;
const model = JSON.parse(fs.readFileSync(modelPath, 'utf8'));
const stats = model.stats;
const categories = model.categories;
const weights = model.weights;
const featureNames = model.feature_names;
const thresholds = model.thresholds;
const nameToWeight = Object.fromEntries(featureNames.map((name, index) => [name, weights[index]]));

let nullCreditScore = 0;
let nullDefaultFlag = 0;
let negativeRevenue = 0;

for (const row of rows) {
  if (row.credit_score === '') nullCreditScore++;
  if (row.default_flag === '') nullDefaultFlag++;
  if (toNumber(row.annual_revenue_usd) < 0) negativeRevenue++;
}

const blocked = nullCreditScore > 0 || nullDefaultFlag > 0 || negativeRevenue > 0;
if (blocked) {
  return [{
    json: {
      status: 'BLOCKED',
      total_rows: rows.length,
      null_credit_score_count: nullCreditScore,
      null_default_flag_count: nullDefaultFlag,
      negative_revenue_count: negativeRevenue,
      alert_prompt: `Write a 2-sentence plain English alert about the FinanceFlow data quality failure. Missing credit score rows: ${nullCreditScore}. Missing default flag rows: ${nullDefaultFlag}. Negative revenue rows: ${negativeRevenue}. Explain what failed and what the data team should do next.`
    }
  }];
}

const decisionRows = [];
let approveCount = 0;
let reviewCount = 0;
let declineCount = 0;
let totalAtRisk = 0;

for (const row of rows) {
  const vector = [1.0];
  const details = [];

  for (const field of ['business_age_years', 'num_employees', 'annual_revenue_usd', 'loan_amount_usd', 'loan_term_months', 'interest_rate_pct', 'credit_score', 'debt_to_income_ratio']) {
    const rawValue = toNumber(row[field]);
    const scaledValue = (rawValue - stats[field].mean) / stats[field].std;
    vector.push(scaledValue);
    details.push({ feature: `num::${field}`, field, rawValue, encodedValue: scaledValue, kind: 'numeric' });
  }

  for (const field of ['sector', 'loan_purpose', 'state']) {
    for (const category of categories[field]) {
      const encodedValue = row[field] === category ? 1 : 0;
      vector.push(encodedValue);
      if (encodedValue === 1) {
        details.push({ feature: `cat::${field}::${category}`, field, rawValue: category, encodedValue, kind: 'categorical' });
      }
    }
  }

  const score = vector.reduce((sum, value, index) => sum + (weights[index] * value), 0);
  const probability = sigmoid(score);
  const decision = decisionLabel(probability, thresholds);

  if (decision === 'Approve') approveCount++;
  if (decision === 'Review') {
    reviewCount++;
    totalAtRisk += toNumber(row.loan_amount_usd);
  }
  if (decision === 'Decline') {
    declineCount++;
    totalAtRisk += toNumber(row.loan_amount_usd);
  }

  if (decision !== 'Approve') {
    const positiveDrivers = details
      .map((detail) => {
        const contribution = (nameToWeight[detail.feature] || 0) * detail.encodedValue;
        return { detail, contribution };
      })
      .filter((item) => item.contribution > 0)
      .sort((a, b) => b.contribution - a.contribution)
      .slice(0, 2)
      .map((item) => contributionReason(item.detail));

    decisionRows.push({
      json: {
        record_type: 'decision',
        route_to_email: decision === 'Decline',
        status: 'OK',
        loan_id: row.loan_id,
        sector: row.sector,
        state: row.state,
        loan_amount_usd: row.loan_amount_usd,
        credit_score: row.credit_score,
        debt_to_income_ratio: row.debt_to_income_ratio,
        default_probability: Number(probability.toFixed(4)),
        decision,
        underwriter_brief: makeBrief(row, probability, decision, positiveDrivers),
        analyst_email: $env.FINANCEFLOW_ANALYST_EMAIL,
        approve_count: 0,
        review_count: 0,
        decline_count: 0,
        total_at_risk_usd: 0
      }
    });
  }
}

const summaryItem = {
  json: {
    record_type: 'summary',
    route_to_email: false,
    status: 'OK',
    approve_count: approveCount,
    review_count: reviewCount,
    decline_count: declineCount,
    total_at_risk_usd: Number(totalAtRisk.toFixed(2))
  }
};

return [...decisionRows, summaryItem];

